from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build sentence components efficiently
    result_parts = []

    # Start with main identity
    if 'nationality' in predicate_map:
        result_parts.append(f"{main_subject}, a {predicate_map['nationality'][0]} politician")
    elif 'profession' in predicate_map:
        result_parts.append(f"{main_subject}, a {predicate_map['profession'][0]}")
    else:
        result_parts.append(main_subject)

    # Build connected clauses for complex sentence
    connected_info = []

    # Birth info
    if 'birthDate' in predicate_map or 'birthYear' in predicate_map or 'birthPlace' in predicate_map:
        birth_info = []
        if 'birthDate' in predicate_map:
            birth_info.append(f"born on {predicate_map['birthDate'][0]}")
        elif 'birthYear' in predicate_map:
            birth_info.append(f"born in {predicate_map['birthYear'][0]}")
        if 'birthPlace' in predicate_map:
            birth_info.append(f"in {predicate_map['birthPlace'][0]}")
        if birth_info:
            connected_info.append(f"who was {' '.join(birth_info)}")

    # Career info
    if 'office' in predicate_map:
        connected_info.append(f"served as {predicate_map['office'][0]}")
    if 'party' in predicate_map:
        connected_info.append(f"with the {predicate_map['party'][0]} party")
    if 'country' in predicate_map:
        connected_info.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        connected_info.append(f"in {predicate_map['state'][0]}")

    # Military info
    if 'militaryBranch' in predicate_map:
        connected_info.append(f"and served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        connected_info.append(f"holding the rank of {predicate_map['militaryRank'][0]}")
    if 'battle' in predicate_map:
        connected_info.append(f"and participated in the {predicate_map['battle'][0]}")

    # Death info
    if 'deathDate' in predicate_map or 'deathYear' in predicate_map or 'deathPlace' in predicate_map:
        death_info = []
        if 'deathDate' in predicate_map:
            death_info.append(f"died on {predicate_map['deathDate'][0]}")
        elif 'deathYear' in predicate_map:
            death_info.append(f"died in {predicate_map['deathYear'][0]}")
        if 'deathPlace' in predicate_map:
            death_info.append(f"in {predicate_map['deathPlace'][0]}")
        if death_info:
            connected_info.append(f"and {' '.join(death_info)}")

    # Additional info
    if 'almaMater' in predicate_map:
        connected_info.append(f"and studied at {predicate_map['almaMater'][0]}")
    if 'spouse' in predicate_map:
        connected_info.append(f"and was married to {predicate_map['spouse'][0]}")
    if 'predecessor' in predicate_map:
        connected_info.append(f"and was preceded by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        connected_info.append(f"and was succeeded by {predicate_map['successor'][0]}")
    if 'award' in predicate_map:
        connected_info.append(f"and received the {predicate_map['award'][0]}")
    if 'religion' in predicate_map:
        connected_info.append(f"and was a {predicate_map['religion'][0]}")
    if 'residence' in predicate_map:
        connected_info.append(f"with residence at {predicate_map['residence'][0]}")
    if 'activeYearsStartDate' in predicate_map:
        connected_info.append(f"starting in {predicate_map['activeYearsStartDate'][0]}")
    if 'activeYearsEndDate' in predicate_map:
        connected_info.append(f"until {predicate_map['activeYearsEndDate'][0]}")

    # Handle office-related predicates
    if 'inOfficeWhilePresident' in predicate_map:
        connected_info.append(f"during the presidency of {predicate_map['inOfficeWhilePresident'][0]}")
    if 'inOfficeWhilePrimeMinister' in predicate_map:
        connected_info.append(f"during the prime ministership of {predicate_map['inOfficeWhilePrimeMinister'][0]}")
    if 'inOfficeWhileVicePresident' in predicate_map:
        connected_info.append(f"during the vice presidency of {predicate_map['inOfficeWhileVicePresident'][0]}")
    if 'inOfficeWhileGovernor' in predicate_map:
        connected_info.append(f"during the governorship of {predicate_map['inOfficeWhileGovernor'][0]}")
    if 'inOfficeWhileMonarch' in predicate_map:
        connected_info.append(f"during the reign of {predicate_map['inOfficeWhileMonarch'][0]}")

    # Other political info
    if 'hasDeputy' in predicate_map:
        connected_info.append(f"with {predicate_map['hasDeputy'][0]} as deputy")
    if 'region' in predicate_map:
        connected_info.append(f"representing the {predicate_map['region'][0]} region")
    if 'serviceStartYear' in predicate_map:
        connected_info.append(f"starting service in {predicate_map['serviceStartYear'][0]}")
    if 'numberOfVotesAttained' in predicate_map:
        connected_info.append(f"with {predicate_map['numberOfVotesAttained'][0]} votes attained")

    # Combine all parts into one complex sentence
    if connected_info:
        result = result_parts[0] + " " + ", ".join(connected_info)
    else:
        result = result_parts[0]

    return result + "."

# EVOLVE-BLOCK-END
